const { ApolloServer, gql } = require('apollo-server');
const { buildSchema } = require('graphql');

// Define the schema using GraphQL SDL
const typeDefs = gql`
  type User {
    id: ID!
    name: String!
    posts: [Post]
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    comments: [Comment]
    author: User
  }

  type Comment {
    id: ID!
    text: String!
    post: Post
    user: User
  }

  type Query {
    users: [User]
    posts: [Post]
    comments: [Comment]
    user(id: ID!): User
    post(id: ID!): Post
    comment(id: ID!): Comment
  }
`;

// Define the resolvers
const resolvers = {
  User: {
    posts: (user) => fetchPostsByUserId(user.id),
    comments: (user) => fetchCommentsByUserId(user.id)
  },
  Post: {
    comments: (post) => fetchCommentsByPostId(post.id),
    author: (post) => fetchUserById(post.authorId)
  },
  Comment: {
    post: (comment) => fetchPostById(comment.postId),
    user: (comment) => fetchUserById(comment.userId)
  }
};

// Create the Apollo Server
const server = new ApolloServer({ typeDefs, resolvers });

// Start the server
server.listen().then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
});

